    <path d="M54.1621 326.559L125.942 376.559L294.232 916.569L273.442 976.189L189.202 976.149C189.094 976.149 188.99 976.116 188.904 976.054C188.817 975.993 188.754 975.907 188.722 975.809L0.0420414 366.449C-0.0162491 366.256 -0.0138681 366.051 0.0488316 365.861C0.111531 365.671 0.231459 365.506 0.392048 365.389L54.1621 326.559Z" fill="url(#grad_dark)"/>
    <path d="M612.421 504.079C612.468 506.719 612.085 508.646 611.271 509.859C607.945 517.606 605.398 525.519 603.631 533.599L459.441 975.729C459.399 975.868 459.312 975.99 459.195 976.076C459.078 976.163 458.937 976.209 458.791 976.209L273.441 976.189L294.231 916.569C294.578 916.289 294.835 915.916 295.001 915.449C335.255 802.876 375.511 690.306 415.771 577.739C416.158 576.666 416.151 576.136 415.751 576.149L612.421 504.079Z" fill="#6ee7b7"/>
    <path d="M960.793 563.233L827.393 973.609C827.337 973.781 827.229 973.93 827.084 974.036C826.938 974.142 826.763 974.199 826.583 974.199H642.673C642.557 974.199 642.333 973.719 642.333 973.719L813.942 446.119L815.183 446.069C869.944 426.578 924.709 407.088 979.475 387.597L1023 372L960.793 563.233Z" fill="#6ee7b7"/>
    <defs>
      <linearGradient id="grad_dark" x1="147" y1="326" x2="147" y2="976" gradientUnits="userSpaceOnUse">
        <stop stopColor="#6ee7b7"/>
        <stop offset="1" stopColor="#34d399"/>
      </linearGradient>
    </defs>
  </svg>
);

/* ── Scroll reveal ── */
function useReveal() {
  useEffect(() => {
    const io = new IntersectionObserver(
      entries => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('in'); }),
      { threshold: 0.08 }
    );
    document.querySelectorAll('.reveal').forEach(el => io.observe(el));
    return () => io.disconnect();
  }, []);
}

/* ── Copy helper ── */
function useCopy(text) {
  const [ok, set] = useState(false);
  const copy = () => navigator.clipboard.writeText(text).then(() => {
    set(true); setTimeout(() => set(false), 1800);
  });
  return [ok, copy];
}

/* ── Data ── */
const INTEGRATIONS = [
  'OpenAI', 'Anthropic', 'Google Gemini', 'LangChain', 'LlamaIndex',
  'CrewAI', 'AutoGen', 'Pinecone', 'Weaviate', 'Qdrant', 'Redis',
  'PostgreSQL', 'Supabase', 'Modal', 'Vercel AI SDK', 'FastAPI',
];

const EVENTS = [
  { color: '#6ee7b7', method: 'memory.write()',  detail: 'user_42 · intent="book_flight"',   ms: '0ms'  },
  { color: '#a3a3a3', method: 'memory.read()',   detail: 'user_42 · cache hit',               ms: '4ms'  },
  { color: '#6ee7b7', method: 'memory.sync()',   detail: 'pool · 3 replicas reconciled',      ms: '8ms'  },
  { color: '#a3a3a3', method: 'event.emit()',    detail: 'key=last_intent · 2 subscribers',   ms: '2ms'  },
  { color: '#6ee7b7', method: 'memory.scope()', detail: 'tenant_99 · isolated namespace',     ms: '1ms'  },
];

const PROBLEMS = [
  {
    num: '01',
    title: 'State evaporates between calls',
    text: 'Every invocation starts cold. Your agent re-fetches facts, re-derives context, and burns tokens on reasoning it already completed — every single time.',
  },
  {
    num: '02',
    title: 'Redundant compute compounds at scale',
    text: 'Without shared memory, every agent in your pool duplicates work independently. At 1,000 RPM, you pay for the same inference 1,000 times.',
  },
  {
    num: '03',
    title: 'Multi-agent coordination is fragile',
    text: 'Multi-agent pipelines need a shared source of truth. Bolting Redis on top gives you race conditions and stale reads. GlassMem solves this at the primitive level.',
  },
];

const STEPS = [
  { num: '01', title: 'Install in 30 seconds', text: 'npm install glassmem or pip install glassmem. One import. No config files. No cloud setup required.' },
  { num: '02', title: 'Write from any agent',  text: 'mem.write(\'key\', value) persists to your backend instantly — in-memory, Redis, or PostgreSQL, your choice.' },
  { num: '03', title: 'Read from anywhere',    text: 'mem.read(\'key\') returns in under 10ms from any agent instance, any replica, anywhere.' },
  { num: '04', title: 'React to changes',      text: 'mem.on(\'key\', handler) lets agents subscribe to state changes in real time — no polling loops.' },
];

const CODE_LINES = [
  { n: 1,  tokens: [{ c: '#7dd3fc', t: 'import' }, { c: '#e2e8f0', t: ' { GlassMem } ' }, { c: '#7dd3fc', t: 'from' }, { c: '#86efac', t: " 'glassmem'" }] },
  { n: 2,  tokens: [] },
  { n: 3,  tokens: [{ c: '#7dd3fc', t: 'const' }, { c: '#e2e8f0', t: ' mem ' }, { c: '#94a3b8', t: '=' }, { c: '#7dd3fc', t: ' new' }, { c: '#fcd34d', t: ' GlassMem' }, { c: '#e2e8f0', t: '({ backend: ' }, { c: '#86efac', t: "'redis'" }, { c: '#e2e8f0', t: ' })' }] },
  { n: 4,  tokens: [] },
  { n: 5,  tokens: [{ c: '#64748b', t: '// Write from Agent A — persists instantly' }] },
  { n: 6,  tokens: [{ c: '#7dd3fc', t: 'await' }, { c: '#e2e8f0', t: ' mem.' }, { c: '#93c5fd', t: 'write' }, { c: '#e2e8f0', t: "('user_intent', intent)" }] },
  { n: 7,  tokens: [] },
  { n: 8,  tokens: [{ c: '#64748b', t: '// Read from Agent B — 4ms, no cold start' }] },
  { n: 9,  tokens: [{ c: '#7dd3fc', t: 'const' }, { c: '#e2e8f0', t: ' ctx ' }, { c: '#94a3b8', t: '=' }, { c: '#7dd3fc', t: ' await' }, { c: '#e2e8f0', t: " mem." }, { c: '#93c5fd', t: 'read' }, { c: '#e2e8f0', t: "('user_intent')" }] },
  { n: 10, tokens: [] },
  { n: 11, tokens: [{ c: '#64748b', t: '// Subscribe — react without polling' }] },
  { n: 12, tokens: [{ c: '#e2e8f0', t: 'mem.' }, { c: '#93c5fd', t: 'on' }, { c: '#e2e8f0', t: "('user_intent', (val) => agent.update(val))" }] },
];

const FEATURES = [
  { name: 'Sub-10ms reads',        desc: 'Hot-path retrieval served from an in-process cache, with async write-through to the configured backend. Your agents never block on state.' },
  { name: 'CRDT sync',             desc: 'Writes propagate across all replicas using a grow-only CRDT — no manual merging, no last-write-wins surprises.' },
  { name: 'Namespaced isolation',  desc: 'Per-agent, per-session, and per-tenant namespaces are built in. No configuration required to isolate workloads.' },
  { name: 'Streaming events',      desc: 'Every mutation emits a typed event on the internal bus. Build reactive agent pipelines without a single setTimeout.' },
  { name: 'Pluggable backends',    desc: 'In-memory, Redis, PostgreSQL, or Supabase. Swap the backend without changing a line of agent code.' },
  { name: 'OpenTelemetry traces',  desc: 'Full trace context propagated on every read and write. Debug exactly where memory adds latency — no guessing.' },
];

const PLANS = [
  {
    tier: 'Hobby',
    price: '$0', period: '/mo',
    desc: 'For side projects',
    featured: false,
    feats: ['1 project', '100K ops / mo', '1-day TTL', 'In-memory backend', 'Community support'],
  },
  {
    tier: 'Pro',
    price: '$49', period: '/mo',
    desc: 'For production agents',
    featured: true,
    feats: ['Unlimited projects', '10M ops / mo', '90-day TTL', 'Redis + Postgres backends', 'Streaming events', 'Priority support'],
  },
  {
    tier: 'Enterprise',
    price: 'Custom', period: '',
    desc: 'For teams at scale',
    featured: false,
    feats: ['SLA guarantee', 'Unlimited ops', 'Custom TTL', 'VPC deployment', 'SOC 2 compliant', 'Dedicated support'],
  },
];

/* ══════════════════════════════════════════════════
   PAGE
══════════════════════════════════════════════════ */
export function GlassMemPage() {
  useReveal();

  const [scrolled, setScrolled]     = useState(false);
  const [mobOpen, setMobOpen]       = useState(false);
  const [activeEv, setActiveEv]     = useState(0);
  const [copied, copy]              = useCopy('npm install glassmem');

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 8);
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);

  useEffect(() => {
    const t = setInterval(() => setActiveEv(i => (i + 1) % EVENTS.length), 1800);
    return () => clearInterval(t);
  }, []);

  return (
    <div>

      {/* ═══ NAV ═══════════════════════════════════ */}
      <header>
        <nav className="nav" style={{ borderBottomColor: scrolled ? 'rgba(255,255,255,0.1)' : 'rgba(255,255,255,0.08)' }}>
          <div className="nav__row">
            <a href="/" className="nav__logo">
              <Logo size={24} />
              <span className="nav__wordmark">GlassMem</span>
            </a>

            <div className="nav__links">
              {['Features', 'How it works', 'Pricing'].map(l => (
                <a key={l} href={`#${l.toLowerCase().replace(/ /g,'')}`} className="nav__link">{l}</a>
              ))}
              <a href="https://docs.glassmem.ai" className="nav__link">Docs</a>
              <a href="https://github.com/glassmem" className="nav__link">GitHub</a>
            </div>

            <div className="nav__right">
              <a href="#pricing" className="btn btn--ghost btn--sm">Log in</a>
              <a href="#pricing" className="btn btn--em btn--sm">Get started</a>
            </div>

            <button className="nav__mob-toggle" onClick={() => setMobOpen(o => !o)} aria-label="Menu">
              {mobOpen ? '✕' : '☰'}
            </button>
          </div>

          <div className={`nav__mob-menu${mobOpen ? ' open' : ''}`}>
            {['Features', 'How it works', 'Pricing', 'Docs', 'GitHub'].map(l => (
              <a key={l} href={`#${l.toLowerCase().replace(/ /g,'')}`}
                className="nav__mob-link" onClick={() => setMobOpen(false)}>{l}</a>
            ))}
          </div>
        </nav>
      </header>

      {/* ═══ HERO ══════════════════════════════════ */}
      <section className="hero">
        <div className="hero__grid" />
        <div className="hero__fade" />

        <div className="w">
          <div className="hero__inner">

            {/* Left */}
            <div>
              <div className="hero__badge enter">
                <span className="hero__badge-dot" />
                Public beta — v0.4
              </div>

              <h1 className="h1 hero__h1 enter-2">
                Persistent memory<br />for AI agents
              </h1>

              <p className="body-lg hero__sub enter-3">
                Your agents forget everything between calls. GlassMem gives them sub-10ms read/write memory with automatic sync across replicas — without managing any infrastructure.
              </p>

              <div className="hero__ctas enter-4">
                <a href="#pricing" className="btn btn--em btn--lg">Start free</a>
                <a href="https://docs.glassmem.ai" className="btn btn--ghost btn--lg">Read the docs</a>
              </div>

              <button className="hero__install enter-5" onClick={copy}>
                <span className="hero__install-prompt">$</span>
                <span style={{ color: 'rgba(255,255,255,0.7)' }}>npm install glassmem</span>
                <span className="hero__install-hint">{copied ? '✓ copied' : 'copy'}</span>
              </button>
            </div>

            {/* Right — live event panel */}
            <div className="hero__panel">
              <div className="hero__panel-bar">
                <span className="hero__panel-title">
                  <Logo size={14} />
                  GlassMem · live stream
                </span>
                <span className="hero__panel-live">
                  <span className="hero__panel-dot" />
                  LIVE
                </span>
              </div>

              <div className="hero__stats">
                {[
                  { val: '4ms',  lbl: 'avg read latency' },
                  { val: '100%', lbl: 'cache hit rate'   },
                  { val: '3',    lbl: 'active agents'    },
                ].map(s => (
                  <div key={s.lbl} className="hero__stat">
                    <div className="hero__stat-val">{s.val}</div>
                    <div className="hero__stat-lbl">{s.lbl}</div>
                  </div>
                ))}
              </div>

              {EVENTS.map((ev, i) => (
                <div
                  key={i}
                  className="hero__event"
                  style={{ opacity: i === activeEv ? 1 : 0.35, transition: 'opacity 0.4s' }}
                >
                  <span className="hero__event-dot" style={{ background: ev.color }} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div className="hero__event-method" style={{ color: ev.color }}>{ev.method}</div>
                    <div className="hero__event-detail">{ev.detail}</div>
                  </div>
                  <span className="hero__event-time">{ev.ms}</span>
                </div>
              ))}
            </div>

          </div>
        </div>
      </section>

      {/* ═══ STRIP ═════════════════════════════════ */}
      <div className="strip">
        <div className="strip__edge-l" />
        <div className="strip__edge-r" />
        <div className="strip__track">
          {[...INTEGRATIONS, ...INTEGRATIONS].map((name, i) => (
            <div key={i} className="strip__item">
              <span className="strip__dot" />
              {name}
            </div>
          ))}
        </div>
      </div>

      {/* ═══ PROBLEM ═══════════════════════════════ */}
      <section id="Features" className="sec">
        <div className="w">
          <div className="problem__top reveal">
            <div>
              <span className="label">The problem</span>
              <h2 className="h2">Stateless agents<br />are broken by design</h2>
            </div>
            <p className="body-lg" style={{ maxWidth: '48ch' }}>
              AI frameworks give you routing, tool use, and streaming — but no memory. So you bolt on Redis, hand-write sync logic, debug race conditions, and start again when requirements change.
            </p>
          </div>

          <div>
            {PROBLEMS.map((p, i) => (
              <div key={i} className="problem__item reveal" style={{ transitionDelay: `${i * 0.06}s` }}>
                <span className="problem__num mono">{p.num}</span>
                <div>
                  <p className="problem__title">{p.title}</p>
                  <p className="body problem__text">{p.text}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ═══ HOW IT WORKS ══════════════════════════ */}
      <section id="Howitworks" className="sec sec--alt">
        <div className="w">
          <div className="steps__top reveal">
            <div>
              <span className="label">How it works</span>
              <h2 className="h2">One import.<br />Persistent memory.</h2>
            </div>
            <p className="body-lg" style={{ maxWidth: '46ch' }}>
              GlassMem sits between your agent and its state. Reads are served from a local in-process cache. Writes propagate via a conflict-free CRDT layer.
            </p>
          </div>

          <div>
            {STEPS.map((s, i) => (
              <div key={i} className="steps__item reveal" style={{ transitionDelay: `${i * 0.05}s` }}>
                <span className="steps__num">{s.num}</span>
                <div>
                  <p className="steps__title">{s.title}</p>
                  <p className="steps__text">{s.text}</p>
                </div>
              </div>
            ))}
          </div>

          {/* Terminal */}
          <div className="term reveal">
            <div className="term__bar">
              <div className="term__dots">
                <span className="term__dot term__dot--r" />
                <span className="term__dot term__dot--y" />
                <span className="term__dot term__dot--g" />
              </div>
              <span className="term__file">agent.ts</span>
              <span style={{ width: 48 }} />
            </div>
            <div className="term__body">
              {CODE_LINES.map(line => (
                <div key={line.n} className="term__row">
                  <span className="term__ln">{line.n}</span>
                  <span>
                    {line.tokens.map((tok, j) => (
                      <span key={j} style={{ color: tok.c }}>{tok.t}</span>
                    ))}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ═══ FEATURES (sticky split) ═══════════════ */}
      <section id="Features2" className="sec">
        <div className="w">
          <div className="split">
            {/* Left — sticky label + heading */}
            <div className="split__sticky reveal">
              <span className="label">Under the hood</span>
              <h2 className="h2" style={{ marginBottom: 16 }}>
                Built for<br />production agents
              </h2>
              <p className="body-lg" style={{ maxWidth: '42ch' }}>
                GlassMem is not a wrapper around a key-value store. It is a purpose-built memory layer with conflict resolution, streaming events, and full observability.
              </p>
            </div>

            {/* Right — feature list */}
            <div className="split__features">
              {FEATURES.map((f, i) => (
                <div key={i} className="split__feat reveal" style={{ transitionDelay: `${i * 0.05}s` }}>
                  <p className="split__feat-name">{f.name}</p>
                  <p className="body split__feat-desc">{f.desc}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ═══ PRICING ═══════════════════════════════ */}
      <section id="Pricing" className="sec sec--alt">
        <div className="w">
          <div style={{ textAlign: 'center', marginBottom: 52 }} className="reveal">
            <span className="label">Pricing</span>
            <h2 className="h2" style={{ marginBottom: 12 }}>Simple, transparent pricing</h2>
            <p className="body-lg" style={{ maxWidth: '44ch', margin: '0 auto' }}>
              Start free. Scale when your agents do. No hidden costs, no surprise bills.
            </p>
          </div>

          <div className="pricing__grid reveal">
            {PLANS.map((p, i) => (
              <div key={i} className={`plan${p.featured ? ' plan--feat' : ''}`}>
                <div className="plan__tier">
                  {p.tier}
                  {p.featured && <span className="plan__badge">Most popular</span>}
                </div>
                <div className="plan__price">
                  {p.price}<span className="plan__period">{p.period}</span>
                </div>
                <div className="plan__desc">{p.desc}</div>
                <div className="plan__rule" />
                <ul className="plan__feats">
                  {p.feats.map(f => (
                    <li key={f} className="plan__feat">
                      <span className="plan__check">✓</span>
                      {f}
                    </li>
                  ))}
                </ul>
                <a
                  href="#"
                  className={`btn btn--lg${p.featured ? ' btn--em' : ' btn--ghost'}`}
                  style={{ justifyContent: 'center' }}
                >
                  {p.price === 'Custom' ? 'Talk to us' : 'Get started'}
                </a>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ═══ CTA ════════════════════════════════════ */}
      <section className="sec cta">
        <div className="w">
          <div className="cta__inner">
            <div className="reveal">
              <span className="label">Get started</span>
              <h2 className="cta__h2">Give your agents memory today</h2>
              <p className="body-lg cta__sub">
                Stop rebuilding state management from scratch. Ship agents that actually remember context, share state, and improve over time.
              </p>
              <div className="cta__btns">
                <a href="#pricing" className="btn btn--em btn--lg">Start free</a>
                <a href="https://docs.glassmem.ai" className="btn btn--ghost btn--lg">Read the docs</a>
              </div>
              <button className="cta__install" onClick={copy}>
                <span className="cta__install-p">$</span>
                <span style={{ color: 'rgba(255,255,255,0.65)' }}>npm install glassmem</span>
                <span className="hero__install-hint">{copied ? '✓ copied' : 'copy'}</span>
              </button>
            </div>

            <div className="cta__checklist reveal">
              {[
                'Free tier — no credit card required',
                'Production-ready in under 5 minutes',
                'Works with your existing agent framework',
                'Open-source core, MIT license',
                'Deploy to your own infrastructure',
                'Dedicated support on Pro and Enterprise',
              ].map(item => (
                <div key={item} className="cta__check-item">
                  <span className="cta__check-dot" />
                  {item}
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ═══ FOOTER ════════════════════════════════ */}
      <footer className="footer">
        <div className="footer__inner">
          <div className="footer__brand">
            <Logo size={18} />
            <span className="footer__word">GlassMem</span>
          </div>
          <div className="footer__links">
            {['Docs', 'GitHub', 'Twitter', 'Discord', 'Blog'].map(l => (
              <a key={l} href="#" className="footer__link">{l}</a>
            ))}
          </div>
          <span className="footer__copy">© 2025 GlassMem · MIT License</span>
        </div>
      </footer>

    </div>
  );
}
